99	// commitOn creates a detached-head commit at baseSHA in a throwaway worktree
100	// and returns the new commit SHA. The commit is reachable via object store
101	// but not via any branch in the main repo, simulating what a worker worktree
102	// produces after ExecuteBead cleans up.
103	func (r *landTestRepo) commitOn(baseSHA, path, content, msg string) string {
104		r.t.Helper()
105		wt, err := os.MkdirTemp("", "land-test-wt-*")
106		if err != nil {
107			r.t.Fatal(err)
108		}
109		_ = os.RemoveAll(wt)
110		r.runGit("worktree", "add", "--detach", wt, baseSHA)
111		defer func() {
112			r.runGit("worktree", "remove", "--force", wt)
113			_ = os.RemoveAll(wt)
114		}()
115	
116		if err := os.WriteFile(filepath.Join(wt, path), []byte(content), 0o644); err != nil {
117			r.t.Fatal(err)
118		}
119		cmd := exec.Command("git", "-C", wt, "add", "-A")
120		if out, err := cmd.CombinedOutput(); err != nil {
121			r.t.Fatalf("git add: %s: %v", string(out), err)
122		}
123		cmd = exec.Command("git", "-C", wt, "-c", "user.name=Test", "-c", "user.email=test@test.local", "commit", "-m", msg)
124		if out, err := cmd.CombinedOutput(); err != nil {
125			r.t.Fatalf("git commit: %s: %v", string(out), err)
126		}
127		cmd = exec.Command("git", "-C", wt, "rev-parse", "HEAD")
128		out, err := cmd.Output()
129		if err != nil {
130			r.t.Fatalf("git rev-parse HEAD: %v", err)
131		}
132		sha := strings.TrimSpace(string(out))
133	
134		// Pin the commit with a temporary ref so it survives the worktree
135		// cleanup. The test caller is responsible for Land()-ing it later.
136		ref := fmt.Sprintf("refs/ddx/test-pins/%s", sha[:12])
137		r.runGit("update-ref", ref, sha)
138		return sha
139	}
