184	// mergeCommitCount returns the number of merge commits (commits with >1
185	// parent) reachable from ref. Used to assert merge-commit semantics on the
186	// merge path.
187	func (r *landTestRepo) mergeCommitCount(ref string) int {
188		r.t.Helper()
189		out := r.runGit("log", "--merges", "--format=%H", ref)
190		if out == "" {
191			return 0
192		}
193		return len(strings.Split(out, "\n"))
194	}
