205	// commitParents returns the parent SHAs of sha.
206	func (r *landTestRepo) commitParents(sha string) []string {
207		r.t.Helper()
208		out := r.runGit("rev-list", "--parents", "-n", "1", sha)
209		fields := strings.Fields(out)
210		if len(fields) <= 1 {
211			return nil
212		}
213		return fields[1:]
214	}
