228	// TestLand_HappyPath_FastForward verifies the fast-forward path: currentTip
229	// == BaseRev → target branch is advanced directly to ResultRev with no
230	// merge commit. The worker's commit becomes the new tip unchanged.
231	func TestLand_HappyPath_FastForward(t *testing.T) {
232		r := newLandTestRepo(t)
233		ops := RealLandingGitOps{}
234	
235		// Worker commit at current main.
236		resultSHA := r.commitOn(r.baseSHA, "feature.txt", "hello\n", "feat: hello")
237	
238		req := LandRequest{
239			WorktreeDir:  r.dir,
240			BaseRev:      r.baseSHA,
241			ResultRev:    resultSHA,
242			BeadID:       "ddx-land-happy",
243			AttemptID:    "20260414T000000-aabb",
244			TargetBranch: "main",
245		}
246		land, err := Land(r.dir, req, ops)
247		if err != nil {
248			t.Fatalf("Land: %v", err)
249		}
250		if land.Status != "landed" {
251			t.Fatalf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
252		}
253		if land.Merged {
254			t.Errorf("expected Merged=false on fast path, got true")
255		}
256		if land.NewTip != resultSHA {
257			t.Errorf("expected NewTip=%s, got %s", resultSHA, land.NewTip)
258		}
259		if got := r.resolveRef("refs/heads/main"); got != resultSHA {
260			t.Errorf("main tip = %s, want %s", got, resultSHA)
261		}
262		if n := r.mergeCommitCount("refs/heads/main"); n != 0 {
263			t.Errorf("expected 0 merge commits on main on ff path, got %d", n)
264		}
265		// Replay fidelity: the worker commit's parent must still be BaseRev.
266		parents := r.commitParents(resultSHA)
267		if len(parents) != 1 || parents[0] != r.baseSHA {
268			t.Errorf("worker commit parent = %v, want [%s]", parents, r.baseSHA)
269		}
270		// Worktree sync: feature.txt must exist on disk in the main worktree
271		// after Land() (bug ddx-eaebaffb regression test — pre-fix, the file
272		// was in the index but missing from disk because update-ref bypassed
273		// the working tree).
274		featurePath := filepath.Join(r.dir, "feature.txt")
275		content, readErr := os.ReadFile(featurePath)
276		if readErr != nil {
277			t.Errorf("feature.txt not materialized in working tree after Land(): %v", readErr)
278		} else if string(content) != "hello\n" {
279			t.Errorf("feature.txt content = %q, want %q", string(content), "hello\n")
280		}
281		// git status should show NO phantom deleted/modified entries for feature.txt.
282		statusOut := r.runGit("status", "--porcelain", "feature.txt")
283		if strings.TrimSpace(statusOut) != "" {
284			t.Errorf("git status after Land() shows unexpected entry for feature.txt: %q", statusOut)
285		}
286	}
