535	// TestLand_MergeRequired verifies the merge path: the target has advanced
536	// since the worker started. Land() creates a merge commit whose parents are
537	// [currentTip, workerSHA], and critically the worker's own commit is NOT
538	// rewritten — its parent is still baseSHA so replay sees the original inputs.
539	func TestLand_MergeRequired(t *testing.T) {
540		r := newLandTestRepo(t)
541		ops := RealLandingGitOps{}
542	
543		// Worker branches off baseSHA.
544		workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature-content\n", "feat: worker")
545	
546		// Meanwhile, a sibling lands a commit on main directly.
547		siblingSHA := r.commitOn(r.baseSHA, "sibling.txt", "sibling-content\n", "feat: sibling")
548		r.runGit("update-ref", "refs/heads/main", siblingSHA)
549		r.syncWorkTreeFrom(r.baseSHA)
550	
551		// Now land the worker's result. currentTip = siblingSHA != baseSHA → merge.
552		req := LandRequest{
553			WorktreeDir:  r.dir,
554			BaseRev:      r.baseSHA,
555			ResultRev:    workerSHA,
556			BeadID:       "ddx-land-merge",
557			AttemptID:    "20260414T000001-ccdd",
558			TargetBranch: "main",
559		}
560		land, err := Land(r.dir, req, ops)
561		if err != nil {
562			t.Fatalf("Land: %v", err)
563		}
564		if land.Status != "landed" {
565			t.Fatalf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
566		}
567		if !land.Merged {
568			t.Errorf("expected Merged=true on sibling-advanced tip, got false")
569		}
570		if land.NewTip == workerSHA {
571			t.Errorf("expected NewTip to be the merge commit (different from worker %s), got same SHA", workerSHA)
572		}
573		if got := r.resolveRef("refs/heads/main"); got != land.NewTip {
574			t.Errorf("main tip = %s, want %s", got, land.NewTip)
575		}
576		// Exactly one merge commit was created.
577		if n := r.mergeCommitCount("refs/heads/main"); n != 1 {
578			t.Errorf("expected 1 merge commit on main after merge path, got %d", n)
579		}
580		// The merge commit's parents must be [siblingSHA, workerSHA] (in that order:
581		// `git merge --no-ff` from a worktree at currentTip produces [currentTip, incoming]).
582		parents := r.commitParents(land.NewTip)
583		if len(parents) != 2 {
584			t.Fatalf("merge commit should have 2 parents, got %v", parents)
585		}
586		if parents[0] != siblingSHA {
587			t.Errorf("merge commit parent[0] = %s, want currentTip %s", parents[0], siblingSHA)
588		}
589		if parents[1] != workerSHA {
590			t.Errorf("merge commit parent[1] = %s, want workerSHA %s", parents[1], workerSHA)
591		}
592		// Replay fidelity: the worker's commit is NOT rewritten — its parent is still baseSHA.
593		workerParents := r.commitParents(workerSHA)
594		if len(workerParents) != 1 || workerParents[0] != r.baseSHA {
595			t.Errorf("worker commit parent = %v, want [%s] (replay fidelity)", workerParents, r.baseSHA)
596		}
597		// main should have baseSHA + siblingSHA + workerSHA + merge commit = 4 commits.
598		if n := r.commitCount("refs/heads/main"); n != 4 {
599			t.Errorf("expected 4 commits on main (base+sibling+worker+merge), got %d", n)
600		}
601	}
