603	// TestLand_MergeConflict verifies that a merge conflict is handled cleanly:
604	// the target branch is untouched, the original ResultRev is preserved under
605	// refs/ddx/iterations/, and no stale worktree is left behind.
606	func TestLand_MergeConflict(t *testing.T) {
607		r := newLandTestRepo(t)
608		ops := RealLandingGitOps{}
609	
610		// Worker edits feature.txt starting from baseSHA.
611		workerSHA := r.commitOn(r.baseSHA, "feature.txt", "worker-version\n", "feat: worker")
612	
613		// Sibling edits the SAME file (feature.txt) on main. Merging the worker
614		// commit into this tip will conflict.
615		siblingSHA := r.commitOn(r.baseSHA, "feature.txt", "sibling-version\n", "feat: sibling")
616		r.runGit("update-ref", "refs/heads/main", siblingSHA)
617		r.syncWorkTreeFrom(r.baseSHA)
618	
619		req := LandRequest{
620			WorktreeDir:  r.dir,
621			BaseRev:      r.baseSHA,
622			ResultRev:    workerSHA,
623			BeadID:       "ddx-land-conflict",
624			AttemptID:    "20260414T000002-eeff",
625			TargetBranch: "main",
626		}
627		land, err := Land(r.dir, req, ops)
628		if err != nil {
629			t.Fatalf("Land: %v", err)
630		}
631		if land.Status != "preserved" {
632			t.Fatalf("expected status=preserved on conflict, got %q", land.Status)
633		}
634		if land.PreserveRef == "" || !strings.HasPrefix(land.PreserveRef, "refs/ddx/iterations/ddx-land-conflict/") {
635			t.Errorf("expected preserve ref under refs/ddx/iterations/ddx-land-conflict/, got %q", land.PreserveRef)
636		}
637		if land.Reason == "" {
638			t.Errorf("expected non-empty Reason on preserve, got empty")
639		}
640		// Target branch must be unchanged from the sibling commit.
641		if got := r.resolveRef("refs/heads/main"); got != siblingSHA {
642			t.Errorf("main tip = %s, want %s (unchanged)", got, siblingSHA)
643		}
644		// Preserve ref must exist and resolve to the original worker SHA.
645		if got := r.resolveRef(land.PreserveRef); got != workerSHA {
646			t.Errorf("preserve ref resolves to %s, want %s", got, workerSHA)
647		}
648		// No stale ddx-land-wt-* worktrees (the merge ran in a temp worktree
649		// which must have been cleaned up on abort).
650		wtList := r.runGit("worktree", "list", "--porcelain")
651		for _, line := range strings.Split(wtList, "\n") {
652			if strings.HasPrefix(line, "worktree ") && strings.Contains(line, "ddx-land-wt-") {
653				t.Errorf("stale land worktree left behind: %q", line)
654			}
655		}
656	}
