928	// TestLand_ConcurrentSubmissions_Serialized spawns N concurrent Land() calls
929	// through a single coordinator-like serialization (sync.Mutex) and asserts
930	// that (a) all N worker commits are reachable from main, (b) each non-first
931	// submission took the merge path and produced a merge commit, and (c) every
932	// worker commit's original parent is preserved (replay fidelity).
933	//
934	// This is a direct test of the "single-writer" contract the server
935	// coordinator enforces, plus the replay-fidelity invariant of the
936	// merge-over-rebase design.
937	func TestLand_ConcurrentSubmissions_Serialized(t *testing.T) {
938		r := newLandTestRepo(t)
939		ops := RealLandingGitOps{}
940	
941		const N = 5
942		// Prepare N worker commits, each branching off the original baseSHA.
943		// Each touches a distinct file so merges always complete cleanly.
944		workerSHAs := make([]string, N)
945		for i := 0; i < N; i++ {
946			workerSHAs[i] = r.commitOn(r.baseSHA, fmt.Sprintf("worker-%d.txt", i), fmt.Sprintf("content-%d\n", i), fmt.Sprintf("feat: worker %d", i))
947		}
948	
949		// Serialize submissions through a mutex — this simulates the coordinator
950		// goroutine. Spawn concurrently so we exercise the lock ordering too.
951		var mu sync.Mutex
952		var wg sync.WaitGroup
953		results := make([]*LandResult, N)
954		errs := make([]error, N)
955		for i := 0; i < N; i++ {
956			i := i
957			wg.Add(1)
958			go func() {
959				defer wg.Done()
960				mu.Lock()
961				defer mu.Unlock()
962				req := LandRequest{
963					WorktreeDir:  r.dir,
964					BaseRev:      r.baseSHA, // all submissions think they branched off the original base
965					ResultRev:    workerSHAs[i],
966					BeadID:       fmt.Sprintf("ddx-concurrent-%02d", i),
967					AttemptID:    fmt.Sprintf("20260414T00%04d-%02d", i, i),
968					TargetBranch: "main",
969				}
970				results[i], errs[i] = Land(r.dir, req, ops)
971			}()
972		}
973		wg.Wait()
974	
975		for i, err := range errs {
976			if err != nil {
977				t.Errorf("submission %d: Land returned error: %v", i, err)
978			}
979			if results[i] == nil || results[i].Status != "landed" {
980				t.Errorf("submission %d: expected landed, got %+v", i, results[i])
981			}
982		}
983	
984		// Exactly one submission took the ff path (the first one under lock);
985		// every subsequent one saw an advanced tip and took the merge path.
986		merged := 0
987		ff := 0
988		for _, res := range results {
989			if res == nil {
990				continue
991			}
992			if res.Merged {
993				merged++
994			} else {
995				ff++
996			}
997		}
998		if ff != 1 {
999			t.Errorf("expected exactly 1 fast-forward submission, got %d", ff)
1000		}
1001		if merged != N-1 {
1002			t.Errorf("expected %d merged submissions, got %d", N-1, merged)
1003		}
1004	
1005		// All N worker commits must be reachable from main.
1006		for i, sha := range workerSHAs {
1007			if !r.shaReachable("refs/heads/main", sha) {
1008				t.Errorf("worker %d commit %s not reachable from main", i, sha)
1009			}
1010		}
1011	
1012		// Replay fidelity: every worker commit must still have parent == baseSHA.
1013		for i, sha := range workerSHAs {
1014			parents := r.commitParents(sha)
1015			if len(parents) != 1 || parents[0] != r.baseSHA {
1016				t.Errorf("worker %d commit parent = %v, want [%s]", i, parents, r.baseSHA)
1017			}
1018		}
1019	
1020		// Each non-ff submission produced exactly one merge commit on main.
1021		if n := r.mergeCommitCount("refs/heads/main"); n != N-1 {
1022			t.Errorf("expected %d merge commits on main, got %d", N-1, n)
1023		}
1024	}
