1033	
1034		// Seed a commit directly on the bare origin so the remote main is
1035		// ahead of the local main.
1036		//
1037		// To create a commit on a bare repo, push from a throwaway clone.
1038		sideDir, err := os.MkdirTemp("", "land-side-*")
1039		if err != nil {
1040			t.Fatal(err)
1041		}
1042		defer os.RemoveAll(sideDir)
1043		runCmd := func(dir string, args ...string) {
1044			c := exec.Command("git", append([]string{"-C", dir}, args...)...)
1045			out, cerr := c.CombinedOutput()
1046			if cerr != nil {
1047				t.Fatalf("git %s: %s: %v", strings.Join(args, " "), string(out), cerr)
1048			}
1049		}
1050		runCmd("", "clone", r.origin, sideDir)
1051		runCmd(sideDir, "config", "user.name", "Side")
1052		runCmd(sideDir, "config", "user.email", "side@test.local")
1053		if err := os.WriteFile(filepath.Join(sideDir, "remote-only.txt"), []byte("remote\n"), 0o644); err != nil {
1054			t.Fatal(err)
1055		}
1056		runCmd(sideDir, "add", "-A")
1057		runCmd(sideDir, "commit", "-m", "remote: seed")
1058		runCmd(sideDir, "push", "origin", "main")
1059	
1060		// Now the origin has advanced beyond the local r.dir/main. To force a
1061		// push failure specifically, we need the local main to be advanced
1062		// ahead of origin AND the push to conflict. Simplest construction:
1063		// disable the auto-fetch by marking the remote as unreachable, then
1064		// land a local commit via the ff path and watch the push fail.
1065		r.runGit("remote", "set-url", "origin", "/nonexistent/path/"+filepath.Base(r.dir))
1066	
1067		workerSHA := r.commitOn(r.baseSHA, "local-only.txt", "local\n", "feat: local")
1068	
1069		req := LandRequest{
1070			WorktreeDir:  r.dir,
1071			BaseRev:      r.baseSHA,
1072			ResultRev:    workerSHA,
1073			BeadID:       "ddx-land-pushff",
1074			AttemptID:    "20260414T000009-pf",
1075			TargetBranch: "main",
1076		}
1077		land, err := Land(r.dir, req, ops)
1078		if err != nil {
1079			t.Fatalf("Land: %v", err)
1080		}
1081		// Local target ref must still advance — push failure is non-fatal.
1082		if land.Status != "landed" {
1083			t.Fatalf("expected status=landed (local) even when push fails, got %q", land.Status)
1084		}
1085		if !land.PushFailed {
1086			t.Errorf("expected PushFailed=true when origin is unreachable, got false")
1087		}
1088		if land.PushError == "" {
1089			t.Errorf("expected non-empty PushError when push fails")
1090		}
1091		if got := r.resolveRef("refs/heads/main"); got != workerSHA {
1092			t.Errorf("local main tip = %s, want %s", got, workerSHA)
1093		}
1094		// Force-push canary: ensure no --force was used. The unreachable path
1095		// makes verification of the remote tricky; instead, we verify that the
1096		// PushError message mentions push (git's own error) and does NOT mention
1097		// "force".
1098		if strings.Contains(strings.ToLower(land.PushError), "--force") {
1099			t.Errorf("PushError mentions --force; Land() must never force-push: %s", land.PushError)
1100		}
1101	}
