1451	// TestLand_MergeRequired_IndexCleanAfterMerge is a regression test for
1452	// ddx-7e659c95. After a successful merge landing (the target branch advanced
1453	// since the worker started), the main worktree's git INDEX must be clean —
1454	// i.e. `git diff --cached --name-only` must return nothing for files the
1455	// bead changed. Before the fix, UpdateRefTo advanced the main branch ref
1456	// without updating the index, leaving staged reverts of the bead's changes.
1457	// When the operator subsequently ran `git commit` (intending only
1458	// beads.jsonl), those phantom staged entries were swept in, undoing the
1459	// bead's work.
1460	//
1461	// The test exercises the index-lock contention scenario: a goroutine holds
1462	// `.git/index.lock` for 2 s while Land() runs. Before the fix,
1463	// SyncWorkTreeToHead silently discarded the lock-contention error and
1464	// returned, leaving the index dirty. After the fix, SyncWorkTreeToHead
1465	// retries until the lock is released and the index is clean.
1466	func TestLand_MergeRequired_IndexCleanAfterMerge(t *testing.T) {
1467		r := newLandTestRepo(t)
1468		ops := RealLandingGitOps{}
1469	
1470		// Pre-seed a tracked file in the initial commit so the worker has
1471		// something to modify (regression requires a modification, not just a
1472		// new file, so that UpdateRefTo dirtying the index is observable).
1473		r.writeFile("tracked.txt", "original content\n")
1474		r.runGit("add", "-A")
1475		r.runGit("commit", "-m", "test: seed tracked file")
1476		r.baseSHA = r.resolveRef("refs/heads/main")
1477	
1478		// Worker modifies tracked.txt (branching off baseSHA).
1479		workerSHA := r.commitOn(r.baseSHA, "tracked.txt", "bead changes\n", "feat: bead updates tracked")
1480	
1481		// Meanwhile, a sibling lands a commit on main (different file, no conflict).
1482		siblingSHA := r.commitOn(r.baseSHA, "sibling.txt", "sibling content\n", "feat: sibling")
1483		r.runGit("update-ref", "refs/heads/main", siblingSHA)
1484		r.syncWorkTreeFrom(r.baseSHA)
1485	
1486		// Create an evidence dir so the full merge+evidence path is exercised.
1487		// (Evidence triggers landingFinalizationWorktree and landEvidence, which
1488		// is the code path that existed when ddx-7e659c95 was filed.)
1489		attemptID := "20260508T000000-7e659c95"
1490		evidenceDir := filepath.Join(".ddx", "executions", attemptID)
1491		fullEvidenceDir := filepath.Join(r.dir, evidenceDir)
1492		if err := os.MkdirAll(fullEvidenceDir, 0o755); err != nil {
1493			t.Fatal(err)
1494		}
1495		if err := os.WriteFile(filepath.Join(fullEvidenceDir, "manifest.json"),
1496			[]byte(`{"attempt_id":"`+attemptID+`"}`), 0o644); err != nil {
1497			t.Fatal(err)
1498		}
1499	
1500		// Simulate operator index-lock contention: hold .git/index.lock so that
1501		// the first git read-tree HEAD call inside SyncWorkTreeToHead fails with
1502		// "Unable to create index.lock: File exists". Before the fix,
1503		// SyncWorkTreeToHead returned silently on this error and the index stayed
1504		// dirty. After the fix it retries until the lock clears.
1505		//
1506		// Timing: Land() takes ~800ms. The syncWorkTreeToHeadGuarded call happens
1507		// near the end (after merge + evidence worktree ops). Hold the lock for
1508		// 2s so it is still present when git read-tree HEAD is attempted; the
1509		// goroutine releases it so that the retry eventually succeeds.
1510		indexLockPath := filepath.Join(r.dir, ".git", "index.lock")
1511		lockFile, err := os.OpenFile(indexLockPath, os.O_CREATE|os.O_EXCL|os.O_WRONLY, 0o644)
1512		if err != nil {
1513			t.Fatalf("could not pre-create index.lock for contention test: %v", err)
1514		}
1515		_ = lockFile.Close()
1516		go func() {
1517			// Hold the lock for 2 s then release it so SyncWorkTreeToHead can retry.
1518			time.Sleep(2 * time.Second)
1519			_ = os.Remove(indexLockPath)
1520		}()
1521	
1522		req := LandRequest{
1523			WorktreeDir:  r.dir,
1524			BaseRev:      r.baseSHA,
1525			ResultRev:    workerSHA,
1526			BeadID:       "ddx-7e659c95",
1527			AttemptID:    attemptID,
1528			TargetBranch: "main",
1529			EvidenceDir:  filepath.ToSlash(evidenceDir),
1530		}
1531		land, err := Land(r.dir, req, ops)
1532		if err != nil {
1533			t.Fatalf("Land: %v", err)
1534		}
1535		if land.Status != "landed" {
1536			t.Fatalf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
1537		}
1538		if !land.Merged {
1539			t.Fatalf("expected Merged=true on merge path")
1540		}
1541	
1542		// AC2: after Land() returns, the main worktree index must be clean.
1543		// Specifically, `git diff --cached --name-only` must be empty: no
1544		// staged changes (including no phantom revert of tracked.txt).
1545		cached := r.runGit("diff", "--cached", "--name-only")
1546		if strings.TrimSpace(cached) != "" {
1547			t.Errorf("ddx-7e659c95 regression: main worktree index is dirty after merge landing.\n"+
1548				"Staged changes:\n%s\n"+
1549				"These phantom staged entries cause subsequent operator commits to "+
1550				"undo the bead's work.", cached)
1551		}
1552	
1553		// AC1: no pre-merge revert for tracked.txt in git status.
1554		statusOut := r.runGit("status", "--porcelain", "tracked.txt")
1555		if strings.TrimSpace(statusOut) != "" {
1556			t.Errorf("ddx-7e659c95 regression: tracked.txt has unexpected status after merge landing: %q", statusOut)
1557		}
1558	
1559		// Sanity: main tip must equal the evidence commit (or the merge commit if
1560		// no evidence was committed, but evidence is set here).
1561		if land.NewTip == "" {
1562			t.Fatalf("NewTip must not be empty after successful land")
1563		}
1564		if got := r.resolveRef("refs/heads/main"); got != land.NewTip {
1565			t.Errorf("main tip = %s, want land.NewTip %s", got, land.NewTip)
1566		}
1567	
1568		// Sanity: tracked.txt on disk must reflect the bead's change.
1569		content, readErr := os.ReadFile(filepath.Join(r.dir, "tracked.txt"))
1570		if readErr != nil {
1571			t.Errorf("tracked.txt not present in working tree after merge landing: %v", readErr)
1572		} else if string(content) != "bead changes\n" {
1573			t.Errorf("tracked.txt content = %q after merge landing, want bead changes", string(content))
1574		}
1575	}
