178	func reorderQueueBucket(bucket []Bead, targetID, otherID string, op queueOp) []Bead {
179		if len(bucket) <= 1 {
180			return bucket
181		}
182	
183		targetIdx := -1
184		otherIdx := -1
185		for i, bead := range bucket {
186			switch bead.ID {
187			case targetID:
188				targetIdx = i
189			case otherID:
190				otherIdx = i
191			}
192		}
193		if targetIdx < 0 {
194			return bucket
195		}
196	
197		out := append([]Bead(nil), bucket...)
198		target := out[targetIdx]
199		out = append(out[:targetIdx], out[targetIdx+1:]...)
200	
201		switch op {
202		case queueOpTop:
203			return append([]Bead{target}, out...)
204		case queueOpMoveBefore, queueOpMoveAfter:
205			if otherIdx < 0 || targetID == otherID {
206				return bucket
207			}
208			if targetIdx < otherIdx {
209				otherIdx--
210			}
211			insertAt := otherIdx
212			if op == queueOpMoveAfter {
213				insertAt++
214			}
215			if insertAt < 0 {
216				insertAt = 0
217			}
218			if insertAt > len(out) {
219				insertAt = len(out)
220			}
221			out = append(out, Bead{})
222			copy(out[insertAt+1:], out[insertAt:])
223			out[insertAt] = target
224			return out
225		default:
226			return bucket
227		}
228	}
