// TestSyncWorkTreeToHead_DoesNotClobberBeadsJSONL is a regression test for
// ddx-2257460f. SyncWorkTreeToHead must never overwrite .ddx/beads.jsonl with
// the version committed in a landed worktree — that version is a stale
// snapshot from claim time. Operator writes (e.g. queue-rank via
// `ddx bead update --set queue-rank=N`) that arrived after the agent's commit
// must survive the post-land sync.
func TestSyncWorkTreeToHead_DoesNotClobberBeadsJSONL(t *testing.T) {
	r := newLandTestRepo(t)
	ops := RealLandingGitOps{}

	// Commit .ddx/beads.jsonl with snapshot content (simulating what the agent
	// writes when it commits claim/close events). fromRev is the commit BEFORE.
	fromRev := r.baseSHA
	snapshotContent := `{"id":"ddx-snap","extra":{"queue-rank":0}}` + "\n"
	if err := os.MkdirAll(filepath.Join(r.dir, ".ddx"), 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(r.dir, ".ddx", "beads.jsonl"), []byte(snapshotContent), 0o644); err != nil {
		t.Fatal(err)
	}
	r.runGit("add", ".ddx/beads.jsonl")
	r.runGit("commit", "-m", "chore: agent claim events")

	// Operator updates queue-rank after the agent's commit (live state).
	liveContent := `{"id":"ddx-snap","extra":{"queue-rank":5}}` + "\n"
	if err := os.WriteFile(filepath.Join(r.dir, ".ddx", "beads.jsonl"), []byte(liveContent), 0o644); err != nil {
		t.Fatal(err)
	}

	if err := ops.SyncWorkTreeToHead(r.dir, fromRev); err != nil {
		t.Fatalf("SyncWorkTreeToHead: %v", err)
	}

	got, err := os.ReadFile(filepath.Join(r.dir, ".ddx", "beads.jsonl"))
	if err != nil {
		t.Fatalf("reading beads.jsonl after sync: %v", err)
	}
	if string(got) != liveContent {
		t.Errorf("beads.jsonl was clobbered by SyncWorkTreeToHead\ngot:  %q\nwant: %q", string(got), liveContent)
	}
}

// TestSyncWorkTreeToHead_DoesNotClobberBeadsArchiveJSONL is the same
// regression test for .ddx/beads-archive.jsonl.
func TestSyncWorkTreeToHead_DoesNotClobberBeadsArchiveJSONL(t *testing.T) {
	r := newLandTestRepo(t)
