// queue_lifecycle_test.go — regression tests for queue-rank preservation
// across every lifecycle operation. Added in ddx-2257460f: without the
// SyncWorkTreeToHead fix, a landed bead's committed beads.jsonl snapshot
// (taken at claim time) would overwrite the live file and silently revert
// operator queue-rank edits. These tests verify the round-trip contract
// at the store level; the git-overwrite bug is covered in execute_bead_land_test.go.

import (
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// setQueueRank is a helper that sets queue-rank=rank via Store.Update.
func setQueueRank(t *testing.T, s *Store, id string, rank int) {
	t.Helper()
	require.NoError(t, s.Update(id, func(b *Bead) {
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		b.Extra["queue-rank"] = rank
	}))
}

// assertQueueRank reads back a bead and asserts parseQueueRank returns wantRank.
func assertQueueRank(t *testing.T, s *Store, id string, wantRank int) {
	t.Helper()
	got, err := s.Get(id)
	require.NoError(t, err)
	rank, ok := parseQueueRank(got.Extra["queue-rank"])
	require.True(t, ok, "parseQueueRank(%v) must succeed", got.Extra["queue-rank"])
	assert.Equal(t, wantRank, rank)
}

// TestQueueRank_PreservedAcrossClaim verifies that Claim does not wipe queue-rank.
func TestQueueRank_PreservedAcrossClaim(t *testing.T) {
	s := newTestStore(t)
	b := &Bead{ID: "ddx-qr-claim", Title: "test", Priority: 2}
	require.NoError(t, s.Create(b))
	setQueueRank(t, s, b.ID, 5)

	require.NoError(t, s.Claim(b.ID, "agent"))

	assertQueueRank(t, s, b.ID, 5)
}

// TestQueueRank_PreservedAcrossUnclaim verifies that Unclaim does not wipe queue-rank.
func TestQueueRank_PreservedAcrossUnclaim(t *testing.T) {
	s := newTestStore(t)
	b := &Bead{ID: "ddx-qr-unclaim", Title: "test", Priority: 2}
	require.NoError(t, s.Create(b))
	setQueueRank(t, s, b.ID, 5)

	require.NoError(t, s.Claim(b.ID, "agent"))
	require.NoError(t, s.Unclaim(b.ID))

	assertQueueRank(t, s, b.ID, 5)
}

// TestQueueRank_PreservedAcrossClose verifies that CloseWithEvidence does not
// wipe queue-rank.
func TestQueueRank_PreservedAcrossClose(t *testing.T) {
	s := newTestStore(t)
	b := &Bead{ID: "ddx-qr-close", Title: "test", Priority: 2}
	require.NoError(t, s.Create(b))
	setQueueRank(t, s, b.ID, 5)

	// Set up evidence so ClosureGate passes.
	require.NoError(t, s.AppendEvent(b.ID, BeadEvent{
		Kind: "execute-bead", Summary: "success", CreatedAt: time.Now().UTC(),
	}))
	require.NoError(t, s.AppendEvent(b.ID, BeadEvent{
		Kind: "review", Summary: "APPROVE", Body: "All AC met", CreatedAt: time.Now().UTC(),
	}))
	require.NoError(t, s.CloseWithEvidence(b.ID, "session-123", "deadbeef"))

	assertQueueRank(t, s, b.ID, 5)
}

// TestQueueRank_PreservedAcrossReopen verifies that Reopen does not wipe queue-rank.
func TestQueueRank_PreservedAcrossReopen(t *testing.T) {
	s := newTestStore(t)
	b := &Bead{ID: "ddx-qr-reopen", Title: "test", Priority: 2}
	require.NoError(t, s.Create(b))
	setQueueRank(t, s, b.ID, 5)

	require.NoError(t, s.Close(b.ID))
	require.NoError(t, s.Reopen(b.ID, "test reopen", ""))

	assertQueueRank(t, s, b.ID, 5)
}

// TestQueueRank_PreservedAcrossReconcile verifies that ReconcileLifecycleMetadata
// does not wipe queue-rank when clearing stale no-changes fields.
func TestQueueRank_PreservedAcrossReconcile(t *testing.T) {
	s := newTestStore(t)
	b := &Bead{
		ID:     "ddx-qr-reconcile",
		Title:  "test",
		Labels: []string{LabelNoChangesUnjustified},
		Extra: map[string]any{
			"queue-rank":        5,
			ExtraRetryAfter:     "2026-01-01T00:00:00Z",
			ExtraLastStatus:     "no_changes",
			ExtraLastDetail:     "agent exited without a commit",
			ExtraNoChangesCount: 2,
			"events": []any{
				map[string]any{"kind": "execute-bead", "summary": "no_changes", "created_at": "2026-01-01T00:00:00Z"},
				map[string]any{"kind": "execute-bead", "summary": "success", "created_at": "2026-01-01T01:00:00Z"},
			},
		},
	}
	require.NoError(t, s.Create(b))

	plans, err := s.ReconcileLifecycleMetadata(ReconcileOptions{Apply: true})
	require.NoError(t, err)
	require.NotEmpty(t, plans, "expected at least one reconcile plan")

	assertQueueRank(t, s, b.ID, 5)
}

// TestQueueRank_PreservedAcrossMigrateLifecycle verifies that MigrateLifecycle
// does not wipe queue-rank when converting legacy lifecycle labels.
func TestQueueRank_PreservedAcrossMigrateLifecycle(t *testing.T) {
	s := newTestStore(t)
	require.NoError(t, s.WriteAll([]Bead{
		{
			ID:        "ddx-qr-migrate",
			Title:     "test",
			Status:    StatusOpen,
			Priority:  2,
			IssueType: DefaultType,
			CreatedAt: time.Now().UTC().Add(-time.Hour),
			UpdatedAt: time.Now().UTC(),
			Labels:    []string{LabelNeedsInvestigation},
			Extra: map[string]any{
				"queue-rank":    5,
				ExtraRetryAfter: "2026-01-01T00:00:00Z",
				ExtraLastStatus: "no_changes",
				ExtraLastDetail: "rerun with a smarter agent; autonomous work remains possible",
			},
		},
	}))

	stats, err := s.MigrateLifecycle()
	require.NoError(t, err)
	assert.Greater(t, stats.RowsChanged, 0, "expected at least one row migrated")

	assertQueueRank(t, s, "ddx-qr-migrate", 5)
}

// TestQueueRank_PreservedAcrossArchive verifies that ArchiveWithEvents does not
// drop queue-rank when moving a closed bead to beads-archive.jsonl.
func TestQueueRank_PreservedAcrossArchive(t *testing.T) {
	s := newTestStore(t)
	b := &Bead{ID: "ddx-qr-archive", Title: "test", Priority: 2}
	require.NoError(t, s.Create(b))
	setQueueRank(t, s, b.ID, 5)
	require.NoError(t, s.Close(b.ID))

	policy := ArchivePolicy{
		Statuses:       []string{StatusClosed},
		MinAge:         0,
		MinActiveCount: 0,
	}
	_, err := s.ArchiveWithEvents(policy)
	require.NoError(t, err)

	// Bead must now be in the archive, not the active collection.
	_, activeErr := s.Get(b.ID)
	require.Error(t, activeErr, "bead should not be in active collection after archive")

	got, err := s.GetWithArchive(b.ID)
	require.NoError(t, err)
	rank, ok := parseQueueRank(got.Extra["queue-rank"])
	require.True(t, ok, "parseQueueRank must succeed on archived bead")
	assert.Equal(t, 5, rank)
}

// TestQueueRank_RoundTripViaJSONL writes a bead with queue-rank as an int,
// persists it to JSONL, reloads, and asserts parseQueueRank succeeds. JSON
// round-trip converts int→float64, which parseQueueRank must handle.
func TestQueueRank_RoundTripViaJSONL(t *testing.T) {
	s := newTestStore(t)
	b := &Bead{
		ID:    "ddx-qr-jsonl",
		Title: "test",
		Extra: map[string]any{"queue-rank": 7},
	}
	require.NoError(t, s.Create(b))

	got, err := s.Get(b.ID)
	require.NoError(t, err)

	rank, ok := parseQueueRank(got.Extra["queue-rank"])
	require.True(t, ok, "parseQueueRank must succeed after JSONL round-trip")
	assert.Equal(t, 7, rank)
}

// TestQueueRank_SetFlagStringRoundTrip simulates `ddx bead update --set
// queue-rank=5` which stores the value as a string. After a JSONL round-trip
// parseQueueRank must still return 5.
func TestQueueRank_SetFlagStringRoundTrip(t *testing.T) {
	s := newTestStore(t)
	b := &Bead{ID: "ddx-qr-setflag", Title: "test", Priority: 2}
	require.NoError(t, s.Create(b))

	// --set stores the value as a string (not bool, not int).
	require.NoError(t, s.Update(b.ID, func(bead *Bead) {
		if bead.Extra == nil {
			bead.Extra = make(map[string]any)
		}
		bead.Extra["queue-rank"] = "5"
	}))

	got, err := s.Get(b.ID)
	require.NoError(t, err)

	rank, ok := parseQueueRank(got.Extra["queue-rank"])
	require.True(t, ok, "parseQueueRank must succeed when value is a string")
	assert.Equal(t, 5, rank)
}

